  1→import {
  2→	buildDateFilter,
  3→	escapeString,
  4→	queryClickhouse,
  5→} from "../clickhouse.js";
  6→
  7→export interface OverviewKPIs {
  8→	distinct_users: number;
  9→	distinct_sessions: number;
 10→	distinct_projects: number;
 11→	distinct_subagents: number;
 12→	distinct_skills: number;
 13→	distinct_slash_commands: number;
 14→}
 15→
 16→export interface UsageTrendData {
 17→	date: string;
 18→	sessions: number;
 19→	active_users: number;
 20→	total_hours: number;
 21→	total_tokens: number;
 22→}
 23→
 24→export interface ModelTokensTrendData {
 25→	date: string;
 26→	model: string;
 27→	total_tokens: number;
 28→	input_tokens: number;
 29→	output_tokens: number;
 30→}
 31→
 32→export interface Insight {
 33→	type: "trend" | "performer" | "alert" | "info";
 34→	severity: "positive" | "warning" | "negative" | "info";
 35→	message: string;
 36→	link: string;
 37→}
 38→
 39→/**
 40→ * Get overview KPI counts: distinct users, sessions, projects, subagents, skills, slash commands
 41→ */
 42→export async function getOverviewKPIs(
 43→	orgId: string,
 44→	days = 7,
 45→): Promise<OverviewKPIs> {
 46→	const org = escapeString(orgId);
 47→	const dateFilter = buildDateFilter(days);
 48→
 49→	const query = `
 50→    SELECT
 51→      uniq(user_id) as distinct_users,
 52→      count() as distinct_sessions,
 53→      uniq(project_path) as distinct_projects,
 54→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN subagent_types as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_subagents,
 55→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN skills as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_skills,
 56→      (SELECT uniqExact(val) FROM rudel.session_analytics ARRAY JOIN slash_commands as val WHERE ${buildDateFilter(days)} AND organization_id = '${org}' AND val != '') as distinct_slash_commands
 57→    FROM rudel.session_analytics
 58→    WHERE ${dateFilter}
 59→      AND organization_id = '${org}'
 60→  `;
 61→
 62→	const result = await queryClickhouse<OverviewKPIs>(query);
 63→	return (
 64→		result[0] || {
 65→			distinct_users: 0,
 66→			distinct_sessions: 0,
 67→			distinct_projects: 0,
 68→			distinct_subagents: 0,
 69→			distinct_skills: 0,
 70→			distinct_slash_commands: 0,
 71→		}
 72→	);
 73→}
 74→
 75→/**
 76→ * Get token usage broken down by model and day
 77→ */
 78→export async function getModelTokensTrend(
 79→	orgId: string,
 80→	days = 30,
 81→): Promise<ModelTokensTrendData[]> {
 82→	const org = escapeString(orgId);
 83→	const dateFilter = buildDateFilter(days);
 84→
 85→	const query = `
 86→    SELECT
 87→      toDate(session_date) as date,
 88→      model_used as model,
 89→      sum(total_tokens) as total_tokens,
 90→      sum(input_tokens) as input_tokens,
 91→      sum(output_tokens) as output_tokens
 92→    FROM rudel.session_analytics
 93→    WHERE ${dateFilter}
 94→      AND organization_id = '${org}'
 95→      AND model_used != ''
 96→      AND model_used != 'unknown'
 97→    GROUP BY date, model
 98→    ORDER BY date ASC, total_tokens DESC
 99→  `;
100→
101→	return queryClickhouse<ModelTokensTrendData>(query);
102→}
103→
104→/**
105→ * Get detailed usage trend data aggregated by day
106→ */
107→export async function getUsageTrendDetailed(
108→	orgId: string,
109→	days = 30,
110→): Promise<UsageTrendData[]> {
111→	const org = escapeString(orgId);
112→	const dateFilter = buildDateFilter(days);
113→
114→	const query = `
115→    SELECT
116→      toDate(session_date) as date,
117→      count() as sessions,
118→      uniq(user_id) as active_users,
119→      round(sum(actual_duration_min) / 60, 2) as total_hours,
120→      sum(total_tokens) as total_tokens
121→    FROM rudel.session_analytics
122→    WHERE ${dateFilter}
123→      AND organization_id = '${org}'
124→    GROUP BY date
125→    ORDER BY date ASC
126→  `;
127→
128→	return queryClickhouse<UsageTrendData>(query);
129→}
130→
131→/**
132→ * Generate rule-based insights from current data
133→ */
134→export async function getOverviewInsights(
135→	orgId: string,
136→	days = 7,
137→): Promise<Insight[]> {
138→	const org = escapeString(orgId);
139→	const insights: Insight[] = [];
140→
141→	const currentPeriodQuery = `
142→    SELECT
143→      count() as total_sessions,
144→      uniq(user_id) as total_users,
145→      round(avg(actual_duration_min), 2) as avg_duration_min
146→    FROM rudel.session_analytics
147→    WHERE ${buildDateFilter(days)}
148→      AND organization_id = '${org}'
149→  `;
150→
151→	const previousDays = Number(days) * 2;
152→	const previousPeriodQuery = `
153→    SELECT
154→      count() as total_sessions,
155→      uniq(user_id) as total_users,
156→      round(avg(actual_duration_min), 2) as avg_duration_min
157→    FROM rudel.session_analytics
158→    WHERE session_date >= now64(3) - INTERVAL ${previousDays} DAY
159→      AND session_date < now64(3) - INTERVAL ${Number(days)} DAY
160→      AND organization_id = '${org}'
161→  `;
162→
163→	interface PeriodStats {
164→		total_sessions: number;
165→		total_users: number;
166→		avg_duration_min: number;
167→	}
168→
169→	const [currentData, previousData] = await Promise.all([
170→		queryClickhouse<PeriodStats>(currentPeriodQuery),
171→		queryClickhouse<PeriodStats>(previousPeriodQuery),
172→	]);
173→
174→	const current = currentData[0];
175→	const previous = previousData[0] || { total_sessions: 0 };
176→
177→	// Insight 1: Session trend analysis
178→	if (current && previous) {
179→		const sessionChange =
180→			previous.total_sessions > 0
181→				? ((current.total_sessions - previous.total_sessions) /
182→						previous.total_sessions) *
183→					100
184→				: 0;
185→
186→		if (Math.abs(sessionChange) >= 10) {
187→			const direction = sessionChange > 0 ? "up" : "down";
188→			const severity = sessionChange > 0 ? "positive" : "warning";
189→			insights.push({
190→				type: "trend",
191→				severity,
192→				message: `Team activity ${direction} ${Math.abs(sessionChange).toFixed(1)}% this week`,
193→				link: "/dashboard/team",
194→			});
195→		}
196→	}
197→
198→	// Insight 2: Top performer identification
199→	const topPerformerQuery = `
200→    SELECT
201→      user_id,
202→      count() as sessions,
203→      round(sum(actual_duration_min) / 60, 1) as total_hours
